    <div className="App">
     <>
    
<section className="banner py-5">
  <div className="container">
    <div className="row align-items-center">
      <div className="col-md-6">
<h2 className='text-dark '>i am sakshi jain</h2>
<p className='mb-0 '>Bootstrap 5 Templates - Free Bootstrap Themes for Responsive & Optimized HTML5 Websites. Admin & Dashboard. Bootstrap 5. eCommerce. Tailwind CSS. Landing Pages</p>
      </div>
      <div className='col-md-6'>
<div className=''><img src={img} className="w-100"/></div>
      </div>
    </div>
  </div>
</section>
      </>
    </div>
  );
}

